mapper.insert:
/** UsptStdrBhExmntDao.insert */
insert into uspt_stdr_bh_exmnt
							(
								bh_exmnt_id
								, stdr_bsns_cd
								, bh_exmnt_div_nm
								, creator_id
								, created_dt
								, updater_id
								, updated_dt
							)
					values	(
								#{bhExmntId}
								, #{stdrBsnsCd}
								, #{bhExmntDivNm}
								, #{creatorId}
								, #{createdDt}
								, #{updaterId}
								, #{updatedDt}
							)

mapper.update:
/** UsptStdrBhExmntDao.update */
update uspt_stdr_bh_exmnt
set
	updater_id = #{updaterId}
	, updated_dt = #{updatedDt}
	, bh_exmnt_div_nm = #{bhExmntDivNm}
where
	bh_exmnt_id = #{bhExmntId}
	and stdr_bsns_cd = #{stdrBsnsCd}

mapper.delete:
/** UsptStdrBhExmntDao.delete */
delete from uspt_stdr_bh_exmnt
where
	bh_exmnt_id = #{bhExmntId}
	and stdr_bsns_cd = #{stdrBsnsCd}
